5	const MAIN_BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	};
11	
12	const COMPONENT_TYPES = new Set(["rune"]);
13	const COMPONENT_SINGLE_PREMIUM = 25;
14	const COMPONENT_BLOCK_PREMIUM = 60;
15	
16	const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);
17	
18	const itemsBasePremium = (items: { type: string }[]): number => {
19	  let total = 0;
20	  const componentCounts: Record<string, number> = {};
21	  for (const item of items) {
22	    if (isComponent(item.type)) {
23	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
24	    } else {
25	      total += MAIN_BASE_PREMIUMS[item.type];
26	    }
27	  }
28	  for (const count of Object.values(componentCounts)) {
29	    const blocks = Math.floor(count / 3);
30	    const singles = count % 3;
31	    total += blocks * COMPONENT_BLOCK_PREMIUM + singles * COMPONENT_SINGLE_PREMIUM;
32	  }
33	  return total;
34	};
35	
36	const roundUp = (value: number): number => {
37	  const epsilon = 1e-9;
38	  return Math.ceil(value - epsilon);
39	};
40	
41	const FIRST_INSURANCE_SURCHARGE = 1.1;
42	const PROCESSING_FEE = 5;
43	
44	export const run = (input: Input): unknown => {
45	  const results = input.steps.map((step) => {
46	    const base = itemsBasePremium(step.items);
47	    const withFirstInsurance = base * FIRST_INSURANCE_SURCHARGE;
48	    const premium = roundUp(withFirstInsurance) + PROCESSING_FEE;
49	    return { premium };
50	  });
51	  return { results };
52	};
